import React, { useState } from 'react';
import api from '../services/api';

export default function SurgePanel() {
  const user    = JSON.parse(localStorage.getItem('zipride_user') || '{}');
  const isAdmin = user.role === 'ADMIN';

  const [form,    setForm]    = useState({ zone:'', baseFare:'100' });
  const [result,  setResult]  = useState(null);
  const [zoneMap, setZoneMap] = useState(null);
  const [loading, setLoading] = useState(false);

  const compute = async e => {
    e.preventDefault(); setLoading(true); setResult(null);
    try {
      const { data } = await api.post('/api/surge/compute', { zone: form.zone, baseFare: parseFloat(form.baseFare) });
      setResult(data);
    } catch (err) { setResult({ message: err.response?.data?.message || 'Error' }); }
    finally { setLoading(false); }
  };

  const fetchZoneMap = async () => {
    try { const { data } = await api.get('/api/surge/by-zone'); setZoneMap(data); } catch {}
  };

  return (
    <>
      {/* ── DRIVER + ADMIN: Compute Surge ───────────────────────── */}
      <div className="panel">
        <div className="panel-header">
          <h3>Compute Surge Pricing</h3>
          <span className="badge">POST /api/surge/compute</span>
        </div>
        <div className="panel-body">
          <form onSubmit={compute}>
            <div className="form-row">
              <div className="form-group"><label>Zone ID</label><input placeholder="ZONE_A" value={form.zone} onChange={e => setForm({...form, zone: e.target.value})} /></div>
              <div className="form-group"><label>Base Fare (₹)</label><input type="number" placeholder="100" value={form.baseFare} onChange={e => setForm({...form, baseFare: e.target.value})} /></div>
            </div>
            <button className="btn-action" type="submit" disabled={loading}>
              {loading && <span className="spinner" />} Calculate Surge
            </button>
          </form>
          {result && (
            <div className="result-card">
              <h4>Surge Result</h4>
              <div className="result-row"><span className="rk">Zone</span><span className="rv">{result.zone}</span></div>
              <div className="result-row"><span className="rk">Active Requests</span><span className="rv">{result.activeRequestCount ?? 0}</span></div>
              <div className="result-row"><span className="rk">Available Drivers</span><span className="rv">{result.availableDriverCount ?? 0}</span></div>
              <div className="result-row"><span className="rk">Supply/Demand Ratio</span><span className="rv">{result.supplyDemandRatio?.toFixed(2) ?? '—'}</span></div>
              <div className="result-row"><span className="rk">Surge Multiplier</span><span className="rv highlight">{result.surgeMultiplier ?? 1.0}×</span></div>
              <div className="result-row"><span className="rk">Final Fare after Surge</span><span className="rv highlight">₹{result.finalFare?.toFixed(2)}</span></div>
            </div>
          )}
        </div>
      </div>

      {/* ── ADMIN ONLY: Surge by Zone map ───────────────────────── */}
      {isAdmin && (
        <div className="panel">
          <div className="panel-header">
            <h3>Surge by Zone</h3>
            <span className="badge">ADMIN only · GET /api/surge/by-zone</span>
          </div>
          <div className="panel-body">
            <button className="btn-action" onClick={fetchZoneMap}>Refresh Zone Map</button>
            {zoneMap && (
              <div className="result-card" style={{ marginTop:20 }}>
                <h4>Current Surge Multipliers</h4>
                {Object.entries(zoneMap).length === 0
                  ? <p style={{ color:'var(--text-muted)', fontSize:13 }}>No zone data available yet.</p>
                  : Object.entries(zoneMap).map(([zone, mult]) => (
                    <div className="result-row" key={zone}>
                      <span className="rk">{zone}</span>
                      <span className="rv" style={{ color: mult > 1 ? 'var(--red)' : 'var(--green)' }}>{mult}×</span>
                    </div>
                  ))
                }
              </div>
            )}
          </div>
        </div>
      )}
    </>
  );
}
